select a.*,b.sNo from lkt_return_order a inner join lkt_order b on a.sNo = b.sNo






    audit_time ${audit_time_sort},

limit #{pageStart},#{pageEnd}

SELECT * FROM lkt_return_order a


    re_time ${re_time_sort},

limit #{pageStart},#{pageEnd}

SELECT a.readd, a.id oId, a.sNo, a.z_price, a.old_total, a.pay, a.user_id,a.otype,a.cpc, a.name, a.mobile, a.offset_balance, a.real_sno, a.subtraction_id, a.mch_id, a.p_sNo, a.status, a.real_sno, m.id detialId, attr.pid goodsId, m.p_name, m.p_price, m.sid attributeId, m.num, m.r_sNo, m.express_id, m.coupon_id detailCouponId, m.arrive_time, m.freight, b.re_type, b.p_id, m.r_status,b.id refundId,m.supplier_settlement,m.after_write_off_num,m.write_time,m.write_time_id,b.r_type,b.r_write_off_num,b.re_money ,m.living_room_id,m.anchor_id FROM lkt_order a, lkt_return_order b, lkt_order_details m, lkt_configure attr
a.store_id = #{store_id} and attr.id = b.sid AND a.sNo = m.r_sNo AND b.p_id = m.id
AND b.id = #{id}

SELECT a.readd, a.id oId, a.sNo, a.z_price, a.old_total, a.pay, a.user_id, a.name, a.mobile, a.offset_balance, a.real_sno, a.subtraction_id, a.mch_id, a.p_sNo, a.STATUS, m.id detialId, m.p_id goodsId, m.p_name, m.p_price, m.sid attributeId, m.num, m.r_sNo, m.express_id, m.coupon_id detailCouponId, m.arrive_time, m.freight, m.r_status,m.supplier_settlement,m.living_room_id,m.anchor_id FROM lkt_order a, lkt_order_details m
a.store_id = #{store_id} AND a.sNo = m.r_sNo
AND m.id = #{id}

mapper.sql:
and a.store_id = #{store_id}
and b.recycle=0
AND p.mch_id = #{mch_id}

    and p.mch_id = #{supplierMchId}

and a.sNo like CONCAT('%',#{likeOrderno},'%')
and a.sNo like CONCAT('%',#{sNo},'%')
# 售后未完成的
and a.r_type not in (100)
AND a.user_id = #{user_id}


        #{type,jdbcType=INTEGER}



    and p.gongyingshang != ''


    and p.gongyingshang = ''

 and b.user_recycle = #{user_recycle}

a.store_id = #{store_id}
and d.id=#{id}
AND (d.sNo like CONCAT('%',#{condition},'%') or u.user_name = #{condition} or u.mobile = #{condition} or u.user_id = #{condition})
and (d.sNo like CONCAT('%',#{likeOrderno},'%') or u.user_id like CONCAT('%',#{likeOrderno},'%'))
and d.sNo=#{orderno}
and o.id=#{orderId}
and o.otype=#{orderType}
or o.otype = #{orderType1}
AND b.mch_id = #{mch_id}
and e.name like CONCAT('%',#{mchName},'%')
AND d.re_time   >=   #{startDate}
AND d.re_time   <=   #{endDate}
AND d.re_type = #{reType}
AND b.gongyingshang = #{supplierId} AND d.re_type != 2 AND d.is_agree = 1
AND b.gongyingshang = ''


        #{type}




        #{type}






    AND d.r_type in(1,3) and d.re_type=1
    AND d.r_type in(4,9,13,15)
    AND d.r_type in(2,5,8) AND d.re_type != 3
    AND d.r_type in(1,3,11) AND d.re_type = 3
    AND d.r_type =12
    AND d.r_type in(5,10) AND d.re_type = 3
    and d.r_type =0

and e.name like CONCAT('%',#{mchName},'%')

a.store_id = #{storeId}
and a.user_id = #{userId}

    and ( a.sNo like concat('%',#{keyword},'%') or b.p_name like concat('%',#{keyword},'%'))


    and a.id=#{returnOrderId}


    and o.otype=#{type}



        #{type}


and a.re_type > 0

mapper.select:
select count(1) from lkt_return_order where store_id = #{storeId}
and user_id = #{userId}

    and p_id = #{orderDetailsId}

and sNo = #{sNo}

select c.actual_total, b.*, lm.name as shop_name, a.pay, c.p_name, c.p_price,c.unit, c.num, s.supplier_name,lpl.cover_map as goodsImgUrl,a.currency_symbol,a.currency_code,a.exchange_rate, CASE WHEN (b.r_type = 1 || b.r_type = 3 || b.r_type=16) AND b.re_type = 1 THEN '退款中' when b.r_type = 4 || b.r_type = 9 || b.r_type = 15 then '退款成功' when (b.r_type = 2 || b.r_type = 5 || b.r_type = 8) and b.re_type != 3 then '退款失败' when (b.r_type = 1 || b.r_type = 3 || b.r_type = 11) and b.re_type = 3 then '换货中' when b.r_type = 12 then '换货成功' when (b.r_type = 5 || b.r_type = 10) and b.re_type = 3 then '换货失败' when b.r_type = 13 then '退款成功' ELSE '审核中' END returnName from lkt_return_order as b left join lkt_order_details as c on b.p_id = c.id left join lkt_order as a on c.r_sNo = a.sNo LEFT JOIN lkt_product_list as lpl on lpl.id = c.p_id LEFT JOIN lkt_mch as lm on lm.id = lpl.mch_id LEFT JOIN lkt_supplier as s on s.id = lpl.gongyingshang
b.re_time ${re_time_sort}, b.r_type ${r_type_sort},
limit #{pageStart},#{pageEnd}

select ifnull(sum(o.num), 0) from lkt_return_order a left join lkt_product_list b on a.pid=b.id inner join  lkt_order
                           o  on  a.sNo=o.sNo


        a.store_id=#{storeid}



            and DATE_FORMAT(a.re_time,'%Y-%m')=#{date}


            and DATE_FORMAT(a.re_time,'%Y-%m-%d')=#{date}




            and b.mch_id=#{mchId}
            and  (b.gongyingshang='' or  b.gongyingshang is null)


            and b.mch_id!=#{mchId}
            and  (b.gongyingshang='' or  b.gongyingshang is null)


            and  b.gongyingshang!=''

select count(DISTINCT b.sNo) from   lkt_return_order a left join lkt_order b on a.sNo=b.sNo

DATE_FORMAT(a.re_time,'%Y-%m-%d') >=#{startDate}
and DATE_FORMAT(a.re_time,'%Y-%m-%d') <=#{endDate} and a.store_id=#{storeid}
and b.otype='GM'
and a.r_type=0

SELECT a.id, a.store_id, a.user_id, a.sNo, a.pay_pal_return_id, a.ali_out_request_no, a.p_id, a.re_type, a.content, a.re_apply_money, a.re_money, a.real_money, a.re_time, a.re_photo, a.audit_time, a.r_content, a.r_type, a.sid, a.pid, a.re_id, a.is_agree, a.r_write_off_num FROM ( SELECT *,ROW_NUMBER() over(partition by pid) as top FROM lkt_return_order WHERE r_type IN ( 4, 9, 13 )
and sNo = #{sNo}
) AS a WHERE a.top < 2
